{
  "formal_minutes": {
    "decisions": [
      "공개 릴리스 목표는 스모크 테스트가 통과될 경우 금요일 15:00 KST로 한다.",
      "packageName 불일치가 발생하면 먼저 패키지 설정을 확인한다.",
      "계약 자체가 잘못된 경우에만 smoke-theme-pack.mjs 스크립트를 검토한다."
    ],
    "non_decisions": {
      "rejected_proposals": [
        "packageName 불일치를 무시하도록 smoke-theme-pack.mjs를 변경하자는 제안은 거부되었다."
      ],
      "internal_stretch_goals": [
        "수요일 릴리스는 확정 일정이 아니라 내부 stretch goal로만 기록한다."
      ],
      "unassigned_or_tentative_items": [
        "README 설치 단계는 가능하면 목요일까지 검토해야 한다는 의견이 있었으나 담당자는 지정되지 않았다.",
        "Hara가 Minjun의 스모크 결과 공유 후 생성된 tarball 경로를 확인하기로 했으나 정확한 마감일은 정해지지 않았다."
      ]
    },
    "risks": [
      "잘못된 tarball 경로는 릴리스를 지연시킬 수 있다.",
      "README 설치 단계가 오래된 상태이면 릴리스 노트가 사용자를 오도할 수 있다."
    ],
    "open_questions": [
      "최종 릴리스 승인 권한자는 누구인가?",
      "릴리스 노트에 내부 수요일 stretch goal을 언급해야 하는가?"
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트를 다시 실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "confirmed",
      "source_certainty": "confirmed_from_fixture"
    },
    {
      "owner": "Doyun",
      "task": "실패 triage note를 action_items.md에 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "confirmed",
      "source_certainty": "confirmed_from_fixture"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 스모크 결과를 게시한 후 생성된 tarball 경로를 확인한다.",
      "due": null,
      "status": "confirmed_no_exact_deadline",
      "source_certainty": "confirmed_from_fixture"
    },
    {
      "owner": null,
      "task": "README 설치 단계를 가능하면 목요일까지 검토한다.",
      "due": "목요일 가능 시",
      "status": "suggested_unassigned",
      "source_certainty": "mentioned_but_no_owner_assigned"
    }
  ],
  "followup_note": {
    "what_to_check_next": [
      "Minjun의 금요일 10:00 KST 스모크 테스트 결과",
      "Doyun의 금요일 12:00 KST action_items.md triage note",
      "스모크 통과 여부에 따른 금요일 15:00 KST 공개 릴리스 가능 여부",
      "Hara의 생성된 tarball 경로 확인 결과",
      "README 설치 단계 검토 담당자 지정 여부",
      "최종 릴리스 승인 권한자",
      "릴리스 노트에 내부 수요일 stretch goal을 포함할지 여부"
    ],
    "what_not_to_invent": [
      "고객 또는 외부 파트너 이름",
      "예산 정보",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 필요 여부",
      "지정되지 않은 담당자",
      "정해지지 않은 마감일"
    ]
  },
  "non_invention_rules": [
    "회의 fixture에 명시된 사실만 사용한다.",
    "고객명, 예산, 보안, 장애, 법무, 담당자, 마감일은 명시되지 않았으면 null 또는 미정으로 둔다.",
    "수요일은 확정 릴리스 일정이 아니라 내부 stretch goal로만 기록한다.",
    "거부된 제안은 결정 사항으로 재분류하지 않는다.",
    "조건부 결정은 조건을 함께 기록한다."
  ]
}
